import math

def bankers_round(x: float) -> int:
    """
    Round x to the nearest integer, with ties (exactly .5) rounded to the nearest even integer.
    Examples: 2.5->2, 3.5->4, 0.5->0, -0.5->0
    """
    if x >= 0:
        lower = math.floor(x)
        frac = x - lower

        # If the fractional part is exactly 0.5
        if frac == 0.5:
            # Round to nearest even
            if lower % 2 == 0:
                return lower
            else:
                return lower + 1
        else:
            # Normal rounding
            return math.floor(x + 0.5)
    else:
        # For negative numbers
        upper = math.ceil(x)
        frac = upper - x

        # If the fractional part is exactly 0.5
        if frac == 0.5:
            # Round to nearest even
            if upper % 2 == 0:
                return upper
            else:
                return upper - 1
        else:
            # Normal rounding
            return math.ceil(x - 0.5)
